#include<bits/stdc++.h>
using namespace std;
int main(){
    long long a[1000001]={0},n,k;
    cin>>n>>k;
    for(int i=2;i<=n;i++){
        long long x;
        cin>>x;
        a[i]=x+a[i-1];
    }
    a[1]=0;
     long long minn=1e200;
    for(int i=1;i<=n;i++){
        if(i+k>n){
             long long x=a[i];
             minn=min(minn,x);
            //cout<<x<<" ";
        }else{
             long long x=a[i]+a[n]-a[i+k];
             minn=min(minn,x);
            //cout<<x<<" ";
        }

    }
    cout<<minn;
    return 0;
}
